const { execFile } = require('child_process');
const path = require('path');

function resizeImage(inputFile, outputFile, dimensions, effects) {
    const validEffects = ['grayscale', 'sepia', 'blur', 'enhance'];
    const sanitizedEffects = effects.filter(effect => validEffects.includes(effect));

    const inputPath = path.resolve(inputFile);
    const outputPath = path.resolve(outputFile);
    const args = ['-resize', dimensions, ...sanitizedEffects.map(effect => `-${effect}`), inputPath, outputPath];

    execFile('magick', args, (error, stdout, stderr) => {
        if (error) {
            console.error(`Error: ${error.message}`);
            return;
        }
        if (stderr) {
            console.error(`stderr: ${stderr}`);
            return;
        }
        console.log(`Image resized and saved to ${outputFile}`);
    });
}